const zipInput = ($node["Webhook"].json["body"]["zipCode"] || "").toString().trim().toLowerCase();
const csvData = $node["Read Binary Files"].json;

let filteredData = [];
const MAX_RESULTS = 50; // We only need 50 rows for Gemini

// EFFICIENT FILTERING: Use a loop and 'break' so we don't process 2 million rows if we don't have to
for (const row of csvData) {
  const zip = (row.zip_code || "").toString().toLowerCase();
  const city = (row.city || "").toString().toLowerCase();
  const state = (row.state || "").toString().toLowerCase();

  if (!zipInput || zip === zipInput || city === zipInput || state === zipInput) {
    filteredData.push(row);
  }

  // Stop once we have enough data to send to Gemini
  if (filteredData.length >= MAX_RESULTS) break;
}

return {
  market_data: filteredData,
  match_count: filteredData.length,
  search_term: zipInput || "United States (General)"
};
